<?php declare(strict_types=1);namespace App\Repositories;final class StreamMetricsRepository extends AbstractRepository{public function record(int $id,array $m):void{$s=$this->pdo()->prepare('INSERT INTO stream_metrics(stream_id,health_score,status,cpu_percent,memory_bytes,encoding_speed,bitrate_kbps,dropped_frames,cpu_steal_percent)VALUES(?,?,?,?,?,?,?,?,?)');$s->execute([$id,$m['score'],$m['status'],$m['cpu']??null,$m['memory']??null,$m['speed']??null,$m['bitrate']??null,$m['dropped']??null,$m['steal']??null]);}public function latest(int $id):?array{$s=$this->pdo()->prepare('SELECT * FROM stream_metrics WHERE stream_id=? ORDER BY id DESC LIMIT 1');$s->execute([$id]);return $s->fetch()?:null;}}
